const c=new Set(["www","com","org","net","edu","gov","app","io","co","dev"]),i={onTask:.57,offTask:.32};function l(n){return n.toLowerCase().replace(/https?:\/\//g," ").replace(/[^a-z0-9]+/g," ").replace(/\s+/g," ").trim()}function u(n){return new URL(n).hostname.toLowerCase().split(/[.-]/g).map(t=>t.trim()).filter(t=>t.length>1&&!c.has(t))}function m(n,e){const t=l(e),a=u(n);return[t,a.join(" ")].filter(Boolean).join(" ").trim()}function f(n,e){if(n.length===0||e.length===0||n.length!==e.length)return 0;let t=0,a=0,s=0;for(let o=0;o<n.length;o+=1)t+=n[o]*e[o],a+=n[o]*n[o],s+=e[o]*e[o];const r=Math.sqrt(a)*Math.sqrt(s);return r===0?0:t/r}function g(n){return n>=i.onTask?"on-task":n<=i.offTask?"off-task":"ambiguous"}export{g as a,m as b,f as c,l as n};
